import { z } from "zod";

export const screenshotRequestSchema = z.object({
  url: z.string().url().max(2048),
  format: z.enum(["png", "pdf"]).optional().default("png"),
  width: z.number().int().min(320).max(3840).optional().default(1280),
  height: z.number().int().min(240).max(2160).optional().default(800),
  fullPage: z.boolean().optional().default(false),
  waitFor: z.number().int().min(0).max(30000).optional().default(0),
});

export const screenshotResponseSchema = z.object({
  image: z.string(),
  format: z.string(),
  width: z.number(),
  height: z.number(),
  url: z.string(),
});

export type ScreenshotRequest = z.infer<typeof screenshotRequestSchema>;
export type ScreenshotResponse = z.infer<typeof screenshotResponseSchema>;
